package Hourplanm1;

public class IsEvenFunction{
		// TODO Auto-generated method stub
		static int isEven(int n) {
	        if (n % 2 == 0) {
	            return 2;
	        } else {
	            return 1;
	        }
	    }

	    public static void main(String[] args) {

	        int n = 12;

	        System.out.println(isEven(n));
	    }
	}

	